import { createForks, teardownForks } from "@tigrisdata/agent-kit";
import {
  S3Client,
  PutObjectCommand,
  ListObjectsV2Command,
} from "@aws-sdk/client-s3";
import { readFile, writeFile } from "fs/promises";

const TigrisEndpoint = "REDACTED";
const Region = "REDACTED";

const normalizeBucketName = (name: string): string =>
  name.toLowerCase().replace(/[^a-z0-9.-]/g, "-");

const createS3Client = (accessKeyId: string, secretAccessKey: string): S3Client =>
  new S3Client({
    region: Region,
    endpoint: TigrisEndpoint,
    credentials: {
      accessKeyId,
      secretAccessKey,
    },
  });

const listKeys = async (client: S3Client, bucket: string): Promise<string[]> => {
  const response = await client.send(
    new ListObjectsV2Command({
      Bucket: bucket,
    }),
  );
  const keys = (response.Contents ?? [])
    .map((item) => item.Key)
    .filter((key): key is string => Boolean(key));
  return keys.sort();
};

const assertKeysMatch = (
  label: string,
  actual: string[],
  expected: string[],
) => {
  const actualJoined = actual.join(", ");
  const expectedJoined = expected.join(", ");
  if (actualJoined !== expectedJoined) {
    throw new Error(
      `${label} keys mismatch. Expected [${expectedJoined}] but found [${actualJoined}].`,
    );
  }
};

const main = async () => {
  const trialIdRaw = (await readFile("/logs/artifacts/trial_id", "utf-8")).trim();
  const sourceBucket = normalizeBucketName(`harbor-isolation-${trialIdRaw}`);
  const forkPrefix = normalizeBucketName(`audit-fork-${trialIdRaw}`);

  const forkSet = await createForks(sourceBucket, 3, {
    prefix: forkPrefix,
    credentials: { role: "Editor" },
  });

  if (forkSet.error) {
    throw new Error(`Failed to create forks: ${forkSet.error.message}`);
  }

  try {
    const uploadTasks = forkSet.forks.map((fork, index) => {
      const client = createS3Client(
        fork.credentials.accessKeyId,
        fork.credentials.secretAccessKey,
      );
      const key = `agent-${index + 1}.out`;
      return client.send(
        new PutObjectCommand({
          Bucket: fork.bucket,
          Key: key,
          Body: `output from ${key}`,
        }),
      );
    });

    await Promise.all(uploadTasks);

    const adminAccessKeyId = process.env.TIGRIS_STORAGE_ACCESS_KEY_ID;
    const adminSecretAccessKey = process.env.TIGRIS_STORAGE_SECRET_ACCESS_KEY;
    if (!adminAccessKeyId || !adminSecretAccessKey) {
      throw new Error("Missing TIGRIS_STORAGE_ACCESS_KEY_ID/SECRET_ACCESS_KEY.");
    }

    const adminClient = createS3Client(adminAccessKeyId, adminSecretAccessKey);
    const sourceKeys = await listKeys(adminClient, sourceBucket);
    const expectedSourceKeys = ["seed1.txt", "seed2.txt"].sort();
    assertKeysMatch("Source bucket", sourceKeys, expectedSourceKeys);

    const forkResults = await Promise.all(
      forkSet.forks.map(async (fork, index) => {
        const client = createS3Client(
          fork.credentials.accessKeyId,
          fork.credentials.secretAccessKey,
        );
        const keys = await listKeys(client, fork.bucket);
        const agentKey = `agent-${index + 1}.out`;
        const expectedKeys = [agentKey, ...expectedSourceKeys].sort();
        assertKeysMatch(`Fork ${fork.bucket}`, keys, expectedKeys);

        return {
          bucket: fork.bucket,
          keys,
        };
      }),
    );

    const report = {
      source_keys: sourceKeys,
      fork_results: forkResults,
    };

    await writeFile(
      "/home/user/isolation/audit.json",
      `${JSON.stringify(report, null, 2)}\n`,
      "utf-8",
    );
  } finally {
    await teardownForks(forkSet);
  }
};

main().catch((error) => {
  console.error(error);
  process.exitCode = 1;
});
